toolArgs.file_text:
.message-item {
    position: relative;
    padding: 0.5rem 0.75rem;
    border-radius: 6px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 0.875rem;
    color: #1a1a1a;
}

.message-time {
    font-size: 0.7rem;
    color: #999;
}

.message-content {
    font-size: 0.875rem;
    color: #333;
    line-height: 1.4;
    word-break: break-word;
}

.reaction-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    background: #f0f0f0;
    border: 1px solid #ddd;
    border-radius: 12px;
    padding: 1px 8px;
    font-size: 0.75rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background: #e0e0ff;
    border-color: #aaf;
}

.thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.75rem;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 2px;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -8px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
}

.action-btn {
    background: none;
    border: none;
    padding: 3px 6px;
    cursor: pointer;
    border-radius: 4px;
    font-size: 0.85rem;
    line-height: 1;
}

.action-btn:hover {
    background: #f0f0f0;
}

.emoji-picker {
    position: absolute;
    top: -8px;
    right: 80px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.15);
    z-index: 10;
}

.emoji-option {
    background: none;
    border: none;
    font-size: 1.1rem;
    padding: 4px 6px;
    cursor: pointer;
    border-radius: 4px;
    line-height: 1;
}

.emoji-option:hover {
    background: #f0f0f0;
}

