    flex-direction: column;
    height: 100%;
    background: linear-gradient(180deg, #3f0e40 0%, #350d36 100%);
    color: #fff;
    overflow: hidden;
}

.sidebar-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid rgba(255,255,255,0.1);
}

.sidebar-header h5 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
