@using sv_7fe28e9443aa45ab88aa6d7541afa3f3.Services
@using sv_7fe28e9443aa45ab88aa6d7541afa3f3.Components.Chat
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="message-list" @ref="scrollContainer">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages…</div>
    }
    @if (!HasMoreMessages && Messages.Count > 0)
    {
        <div class="beginning-marker">Beginning of conversation</div>
    }
    @foreach (var msg in Messages)
    {
        <MessageItem Message="msg"
                     ReplyCount="GetReplyCount(msg.Id)"
                     OnOpenThread="() => OnOpenThread.InvokeAsync(msg.Id)"
                     OnReact="emoji => OnReact.InvokeAsync((msg.Id, emoji))" />
    }
</div>

@code {
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; } = true;
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference scrollContainer;
    private IJSObjectReference? jsModule;
    private DotNetObjectReference<MessageList>? dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            jsModule = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-7fe28e9443aa45ab88aa6d7541afa3f3/chat-scroll.js");
            await jsModule.InvokeVoidAsync("initScrollWatcher", scrollContainer, dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (!IsLoadingMore && HasMoreMessages)
        {
            await OnLoadMore.InvokeAsync();
        }
    }

    public async Task ScrollToBottomAsync()
    {
        if (jsModule is not null)
        {
            await jsModule.InvokeVoidAsync("scrollToBottom", scrollContainer);
        }
    }

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.GetValueOrDefault(messageId);

    public async ValueTask DisposeAsync()
    {
        if (jsModule is not null)
        {
            try
            {
                await jsModule.InvokeVoidAsync("disposeScrollWatcher", scrollContainer);
                await jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        dotNetRef?.Dispose();
    }
}

