@using sv_7fe28e9443aa45ab88aa6d7541afa3f3.Services
@using sv_7fe28e9443aa45ab88aa6d7541afa3f3.Components.Chat

<div class="message-area">
    <div class="message-area-header">
        <h6># @ChannelName</h6>
        @if (!string.IsNullOrWhiteSpace(ChannelDescription))
        {
            <span class="channel-description">@ChannelDescription</span>
        }
    </div>
    <MessageList @ref="messageListRef"
                 Messages="Messages"
                 ThreadReplyCounts="ThreadReplyCounts"
                 IsLoadingMore="IsLoadingMore"
                 HasMoreMessages="HasMoreMessages"
                 OnLoadMore="OnLoadMore"
                 OnOpenThread="OnOpenThread"
                 OnReact="OnReact" />
    <MessageInput Placeholder="@($"Message #{ChannelName}")"
                  ButtonLabel="Send"
                  OnSend="OnSendMessage" />
</div>

@code {
    [Parameter] public string ChannelName { get; set; } = "";
    [Parameter] public string ChannelDescription { get; set; } = "";
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }

    private MessageList? messageListRef;

    public async Task ScrollToBottomAsync()
    {
        if (messageListRef is not null)
        {
            await messageListRef.ScrollToBottomAsync();
        }
    }
}

