arguments.file_text:
@page "/chat"
@layout sv_7fe28e9443aa45ab88aa6d7541afa3f3.Components.Layout.ChatLayout
@rendermode InteractiveServer
@using sv_7fe28e9443aa45ab88aa6d7541afa3f3.Services
@using sv_7fe28e9443aa45ab88aa6d7541afa3f3.Components.Chat
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="activeChannelId"
                        OnChannelSelected="SelectChannelAsync" />
    </div>

    <div class="chat-main @(isThreadOpen ? "" : "chat-main-wide")">
        @if (activeChannel is not null)
        {
            <MessageArea @ref="messageAreaRef"
                         ChannelName="@activeChannel.Name"
                         ChannelDescription="@activeChannel.Description"
                         Messages="messages"
                         ThreadReplyCounts="threadReplyCounts"
                         IsLoadingMore="isLoadingMore"
                         HasMoreMessages="hasMoreMessages"
                         OnLoadMore="LoadMoreMessagesAsync"
                         OnOpenThread="OpenThreadAsync"
                         OnReact="HandleReactionAsync"
                         OnSendMessage="SendMessageAsync" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (isThreadOpen && threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReplyAsync" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private Dictionary<int, int> threadReplyCounts = [];
    private Channel? activeChannel;
    private int activeChannelId;

    private bool isThreadOpen;
    private int? activeThreadRootId;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    private bool isLoadingMore;
    private bool hasMoreMessages = true;
    private const int PageSize = 30;

    private MessageArea? messageAreaRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0].Id);
        }
    }

    private async Task SelectChannelAsync(int channelId)
    {
        if (activeChannelId == channelId) return;

        activeChannelId = channelId;
        activeChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages = [];
        threadReplyCounts = [];
        hasMoreMessages = true;
        CloseThread();

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count >= PageSize;

        await LoadThreadReplyCountsAsync();
        await ChatService.MarkChannelReadAsync(channelId);

        // Update unread count locally
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }

        StateHasChanged();
        await ScrollToBottomAsync();
    }

    private async Task LoadMoreMessagesAsync()
    {
        if (isLoadingMore || !hasMoreMessages) return;
        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannelId, messages.Count, PageSize);
        hasMoreMessages = older.Count >= PageSize;
        messages.InsertRange(0, older);
        await LoadThreadReplyCountsAsync();

        isLoadingMore = false;
        StateHasChanged();
    }

    private async Task SendMessageAsync(string content)
    {
        var msg = await ChatService.SendMessageAsync(activeChannelId, content, null);
        messages.Add(msg);
        StateHasChanged();
        await ScrollToBottomAsync();
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        activeThreadRootId = rootMessageId;
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        isThreadOpen = true;
        StateHasChanged();
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        activeThreadRootId = null;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReplyAsync(string content)
    {
        if (activeThreadRootId is null) return;
        var reply = await ChatService.SendMessageAsync(activeChannelId, content, activeThreadRootId);
        threadReplies.Add(reply);

        // Update reply count
        threadReplyCounts[activeThreadRootId.Value] =
            threadReplyCounts.GetValueOrDefault(activeThreadRootId.Value) + 1;

        StateHasChanged();
    }

    private async Task HandleReactionAsync((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistic update
        var idx = messages.FindIndex(m => m.Id == args.MessageId);
        if (idx >= 0)
        {
            var msg = messages[idx];
            var reactions = msg.Reactions.ToList();
            var existing = reactions.FindIndex(r => r.Emoji == args.Emoji);
            if (existing >= 0)
            {
                var r = reactions[existing];
                reactions[existing] = r with { Users = [..r.Users, "You"] };
            }
            else
            {
                reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
            messages[idx] = msg with { Reactions = reactions };
            StateHasChanged();
        }
    }

    private async Task LoadThreadReplyCountsAsync()
    {
        // Count replies by checking messages with ReplyToId that reference messages in view
        var rootIds = messages.Where(m => m.ReplyToId is null).Select(m => m.Id).ToHashSet();
        foreach (var id in rootIds)
        {
            if (!threadReplyCounts.ContainsKey(id))
            {
                var thread = await ChatService.GetThreadAsync(id);
                if (thread.Count > 0)
                {
                    threadReplyCounts[id] = thread.Count;
                }
            }
        }
    }

    private async Task ScrollToBottomAsync()
    {
        await Task.Yield();
        if (messageAreaRef is not null)
        {
            try { await messageAreaRef.ScrollToBottomAsync(); }
            catch (InvalidOperationException) { }
        }
    }
}

.chat-container {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
    height: 100%;
}

.chat-main {
    flex: 1;
    min-width: 0;
    height: 100%;
}

.chat-main-wide {
    flex: 1;
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
    height: 100%;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #999;
    font-size: 1.1rem;
}

const watchers = new Map();

export function initScrollWatcher(element, dotNetRef) {
    if (!element) return;

    const handler = () => {
        if (element.scrollTop === 0) {
            dotNetRef.invokeMethodAsync('OnScrolledToTop');
        }
    };

    element.addEventListener('scroll', handler, { passive: true });
    watchers.set(element, handler);
}

export function scrollToBottom(element) {
    if (element) {
        element.scrollTop = element.scrollHeight;
    }
}

export function disposeScrollWatcher(element) {
    if (!element) return;
    const handler = watchers.get(element);
    if (handler) {
        element.removeEventListener('scroll', handler);
        watchers.delete(element);
    }
}

